find the shortest path in graph from start to end
"""
stack = [(start, 0)]
while stack:
    (node, cost_so_far) = stack.pop()
    if node == end:
        return cost_so_far
    for neighbor, distance_to_neighbor in graph[node].iteritems():
        if cost_so_far + distance_to_neighbor not in stack:
            stack.append((neighbor, cost_so_far + distance_to_neighbor))
return None
